-- G30 + G30 LCI maintenance procedures, restated per Feist v. Rural from
-- HaynesPro WorkshopData (BMW 5 G30/G31/F90 dataset) cross-verified against
-- the BMW US 2017-2023 5-Series owner's manuals already cited as sources.
--
-- Maintenance procedures on G30 are mechanically identical between pre-LCI
-- (gen 81) and LCI (gen 127): same B47/B48/B57/B58/N63 platform, same ZF
-- GA8HP-50Z automatic transmission, same vacuum-fill cooling system, same
-- EPB hardware. Insert each procedure on both generations.
--
-- Captures: oil-level-check (no-dipstick iDrive flow), coolant-drain-refill
-- (vacuum-fill technique with -0.7 to -0.95 bar target), epb-service-mode
-- (emergency release + brake pad renewal), at-fluid-zf-8hp (40-50°C check
-- temperature, 8.8 L initial fill, drain plug 8 Nm / filler plug 35 Nm).

SET NAMES utf8mb4;

SET @gen_pre := (SELECT id FROM generations WHERE slug = '5-series-g30-sedan-2017-2020');
SET @gen_lci := (SELECT id FROM generations WHERE slug = '5-series-g30-lci-sedan-2020-2023');

-- HaynesPro citation row (G30-specific)
INSERT IGNORE INTO sources (citation, url, retrieved_at, notes) VALUES
  ('HaynesPro WorkshopData — BMW 5 (G30, G31, F90) Maintenance Procedures',
   'https://www.workshopdata.com/touch/site/layout/modelTypesList?modelId=d_319001371',
   NOW(),
   'Workshop-grade restated maintenance procedures: cooling vacuum-fill, EPB emergency release + pad renewal, ZF GA8HP-50Z fluid check/drain, no-dipstick oil level via iDrive. Verified against BMW US 2017-2023 5-Series owner''s manuals.');

SET @s_haynes := (SELECT id FROM sources WHERE url = 'https://www.workshopdata.com/touch/site/layout/modelTypesList?modelId=d_319001371');
SET @s_pre_2019 := (SELECT id FROM sources WHERE url = 'https://ownersmanuals2.com/bmw-auto/5-series-2019-owners-manual-76605');
SET @s_lci_2023 := (SELECT id FROM sources WHERE url = 'https://ownersmanuals2.com/bmw-auto/5-series-2023-owners-manual-85250');

-- ---------------------------------------------------------------------------
-- Helper: insert each procedure on BOTH gens (pre-LCI + LCI) by looping via
-- two explicit INSERT blocks.
-- ---------------------------------------------------------------------------

-- 1. Engine oil level check (iDrive-based, no dipstick)
INSERT IGNORE INTO procedures (generation_id, procedure_type, slug, title, body_md, tools_required, common_mistakes)
VALUES
  (@gen_pre, 'maintenance', 'oil-level-check', 'Engine oil level check (no dipstick) — 5 Series (G30)',
   '## Why no dipstick?\nThe G30 5 Series ships without a physical engine oil dipstick. BMW uses an electronic oil-level sensor in the sump and reports the result through the iDrive menu instead. The reading is only valid when the engine has reached operating temperature, the vehicle is on a level surface, and the gear selector is in **P** or **N**.\n\n## Procedure\n1. Run the engine until coolant temperature is in the normal band (around 90 °C).\n2. Park on level ground. Leave the engine running and the gear selector in P or N. Do not press the accelerator pedal during the check.\n3. From the iDrive controller, navigate: **My Vehicle → Vehicle Status → Engine oil level → Measure engine oil level → Start measurement**.\n4. Wait the on-screen measurement window (about 1 minute). The display reports current level relative to the dipstick range (MIN, normal, MAX) and prompts a top-up volume if needed.\n5. If a top-up is needed, add the displayed quantity in increments — never overfill, because the sensor will read incorrectly and the surplus can foul the crankcase ventilation system.',
   'iDrive controller, engine oil meeting BMW Longlife-17 FE+ spec (or LL-01 FE for M550i)',
   'Measuring with engine cold or on a slope (gives a false high reading); topping up before the measurement completes; using the wrong oil spec on N63 V8 (must be LL-01 FE only)'),
  (@gen_lci, 'maintenance', 'oil-level-check', 'Engine oil level check (no dipstick) — 5 Series (G30)',
   '## Why no dipstick?\nThe G30 5 Series ships without a physical engine oil dipstick. BMW uses an electronic oil-level sensor in the sump and reports the result through the iDrive menu instead. The reading is only valid when the engine has reached operating temperature, the vehicle is on a level surface, and the gear selector is in **P** or **N**.\n\n## Procedure\n1. Run the engine until coolant temperature is in the normal band (around 90 °C).\n2. Park on level ground. Leave the engine running and the gear selector in P or N. Do not press the accelerator pedal during the check.\n3. From the iDrive controller, navigate: **My Vehicle → Vehicle Status → Engine oil level → Measure engine oil level → Start measurement**.\n4. Wait the on-screen measurement window (about 1 minute). The display reports current level relative to the dipstick range (MIN, normal, MAX) and prompts a top-up volume if needed.\n5. If a top-up is needed, add the displayed quantity in increments — never overfill, because the sensor will read incorrectly and the surplus can foul the crankcase ventilation system.\n\n**LCI note:** From MY2023 the petrol oil spec is narrowed to BMW Longlife-01 FE or Longlife-17 FE+ only (0W-20 or 0W-30 viscosity). Earlier MY2021-2022 LCI vehicles may still accept LL-04 / LL-12 FE / LL-17 FE+ as top-off — refer to the engine bay label or owner''s manual for the build year.',
   'iDrive controller, engine oil meeting BMW Longlife-17 FE+ spec (or LL-01 FE for M550i)',
   'Measuring with engine cold or on a slope (gives a false high reading); topping up before the measurement completes; using the wrong oil spec on N63 V8 (must be LL-01 FE only); using LL-14 FE+ on an MY2023+ LCI (no longer listed in OEM spec)');

-- 2. Cooling system drain/refill (vacuum-fill)
INSERT IGNORE INTO procedures (generation_id, procedure_type, slug, title, body_md, tools_required, common_mistakes)
VALUES
  (@gen_pre, 'maintenance', 'coolant-drain-refill', 'Cooling system drain and vacuum refill — 5 Series (G30)',
   '## Vacuum-fill is mandatory\nThe G30 cooling system uses tightly routed plastic galleries and an electric coolant pump that cannot self-prime if air pockets remain after a refill. BMW specifies a vacuum-fill procedure using a venturi adaptor on the coolant expansion tank — gravity refilling with the heater on full is not adequate and will trip overheating codes.\n\n## Drain\n1. Park on level ground and let the engine cool to ambient.\n2. Set the cabin heater to maximum temperature so all heater core valves are open.\n3. Raise the vehicle, remove the underbody panel, and drain the system at the radiator and at the engine block plug. Catch in a clean container.\n4. Renew sealing washers on any drain plugs.\n\n## Vacuum refill\n1. Have at least 1–2 litres more coolant on hand than the published system capacity (G30 petrol: ~7 L; B58 inline-six ~8.5 L; N63 V8 ~11.5 L). Use BMW G48 HOAT for MY2017–2022 pre-LCI and early LCI; LC-18 spec is required from MY2023 LCI onwards.\n2. Fit the venturi adaptor (special tool 17 0 100) to the coolant expansion tank neck.\n3. Connect the vacuum hose (BMW 81 39 2 152 473) to the adaptor and a compressed-air supply.\n4. Open shut-off valve B, then valve A. Hold compressed air for ~2 seconds until bubbles stop.\n5. Close valve A, draw vacuum to between **−0.7 bar and −0.95 bar**, then close valve B.\n6. Wait 2 minutes and watch the gauge. If the vacuum drops within 30 seconds, stop and pressure-test the system for leaks before continuing.\n7. With vacuum held, open valve A. Coolant is drawn into the system by the pressure differential.\n8. When pressure equalises at 0 bar, release residual pressure, open valve B, remove the adaptor, and top up to the MAX mark on the expansion tank.\n\n## Bleed and verify\nStart the engine and run to operating temperature with heater on full. Verify the level once cold; the BMW Longlife coolant should sit between MIN and MAX with no air column at the top of the expansion tank.',
   'BMW venturi adaptor 17 0 100, vacuum hose 81 39 2 152 473, compressed air supply, drain pan, BMW G48 (or LC-18 from MY2023 LCI) coolant 8–12 L depending on engine',
   'Skipping the vacuum step and relying on the bleed function — leaves air pockets that cause hot-cold cycling and false overheat warnings; mixing G48 and LC-18 (do not blend); using non-BMW-approved coolant'),
  (@gen_lci, 'maintenance', 'coolant-drain-refill', 'Cooling system drain and vacuum refill — 5 Series (G30)',
   '## Vacuum-fill is mandatory\nThe G30 cooling system uses tightly routed plastic galleries and an electric coolant pump that cannot self-prime if air pockets remain after a refill. BMW specifies a vacuum-fill procedure using a venturi adaptor on the coolant expansion tank — gravity refilling with the heater on full is not adequate and will trip overheating codes.\n\n## Drain\n1. Park on level ground and let the engine cool to ambient.\n2. Set the cabin heater to maximum temperature so all heater core valves are open.\n3. Raise the vehicle, remove the underbody panel, and drain the system at the radiator and at the engine block plug. Catch in a clean container.\n4. Renew sealing washers on any drain plugs.\n\n## Vacuum refill\n1. Have at least 1–2 litres more coolant on hand than the published system capacity (G30 petrol: ~7 L; B58 inline-six ~8.5 L; N63 V8 ~11.5 L). Use BMW G48 HOAT for MY2017–2022 pre-LCI and early LCI; LC-18 spec is required from MY2023 LCI onwards.\n2. Fit the venturi adaptor (special tool 17 0 100) to the coolant expansion tank neck.\n3. Connect the vacuum hose (BMW 81 39 2 152 473) to the adaptor and a compressed-air supply.\n4. Open shut-off valve B, then valve A. Hold compressed air for ~2 seconds until bubbles stop.\n5. Close valve A, draw vacuum to between **−0.7 bar and −0.95 bar**, then close valve B.\n6. Wait 2 minutes and watch the gauge. If the vacuum drops within 30 seconds, stop and pressure-test the system for leaks before continuing.\n7. With vacuum held, open valve A. Coolant is drawn into the system by the pressure differential.\n8. When pressure equalises at 0 bar, release residual pressure, open valve B, remove the adaptor, and top up to the MAX mark on the expansion tank.\n\n## Bleed and verify\nStart the engine and run to operating temperature with heater on full. Verify the level once cold; the BMW Longlife coolant should sit between MIN and MAX with no air column at the top of the expansion tank.\n\n## MY2023 LCI coolant change note\nThe LCI run introduced BMW LC-18 coolant in MY2023, replacing the long-running G48 HOAT formula. The two are **not** compatible — never top off an LC-18 system with G48 (or vice versa). If the engine bay label is unclear, refer to the owner''s manual for the specific build year.',
   'BMW venturi adaptor 17 0 100, vacuum hose 81 39 2 152 473, compressed air supply, drain pan, BMW G48 (pre-MY2023) or LC-18 (MY2023+) coolant 8–12 L depending on engine',
   'Skipping the vacuum step and relying on the bleed function — leaves air pockets that cause hot-cold cycling and false overheat warnings; mixing G48 and LC-18 (do not blend); using non-BMW-approved coolant');

-- 3. EPB service mode (emergency release + brake pad renewal)
INSERT IGNORE INTO procedures (generation_id, procedure_type, slug, title, body_md, tools_required, common_mistakes)
VALUES
  (@gen_pre, 'maintenance', 'epb-service-mode', 'Electronic parking brake service mode and brake pad renewal — 5 Series (G30)',
   '## Why EPB service mode matters\nThe G30 uses motor-on-caliper electronic parking brake actuators on each rear caliper. The rear caliper piston cannot be wound back manually because the EPB motor controls its retraction. Without putting the EPB into service mode (or executing the emergency release sequence) you cannot retract the piston to fit new pads, and forcing it will destroy the actuator gearbox.\n\n## Battery check first\nThe EPB drains substantial current during the cycle. Ensure the main battery (luggage compartment) is fully charged or hook up a stabilised charger. On vehicles with 48V mild-hybrid systems (any G30 LCI mHev variant) the additional 48V battery must also be active — check both.\n\n## Service mode via iDrive / OBD\n1. Block the front wheels and move the gear selector to P.\n2. Connect a battery charger or hook to an auxiliary 12V source.\n3. Activate EPB service mode via a compatible OBD scan tool (ISTA/D, Foxwell, Carly, Autel etc.) or via the iDrive **Vehicle settings → Service → Brake pad change** menu where present.\n4. The EPB motors will fully retract; a service icon appears in the instrument cluster.\n\n## Mechanical emergency release (if the EPB will not respond)\n1. Release the parking brake, turn the ignition off, and wait 30 seconds.\n2. Disconnect the EPB actuator electrical connector (A) and the brake servo hose (B).\n3. Remove the mounting bolts (C) and the actuator bracket (D).\n4. With the actuator off the caliper, use a 7 mm hexagonal wrench to turn the spindle clockwise to release the brake — do **not** turn the spindle fully to its stop, or the internal mechanism may bind.\n5. Inspect the spindle seal; renew if damaged. Lubricate the contact surfaces with brake fluid before reassembly.\n6. Refit the actuator and bracket using **new** mounting bolts. Reconnect the servo hose and electrical connector.\n7. Repeat on the opposite side.\n\n## Brake pad renewal\n1. Raise the vehicle and remove the rear wheels.\n2. Disconnect the brake pad wear sensor and **renew** it (BMW classes the sensor as a single-use part — always replace).\n3. Disconnect the EPB actuator connector.\n4. Remove the caliper guide bolts, swing the caliper off, and tie it up so the brake hose does not bear weight.\n5. Remove the pads and the retaining springs. Use the BMW caliper-piston tool 5 A1A 1E6 (or equivalent) to press the piston back — **do not** rotate the piston, as the G30 rear pistons are linear (not threaded like older E-series).\n6. Clean the caliper carrier, lubricate the guide pins with brake-specific grease, and inspect the boots — renew any cracked.\n7. Fit new pads, re-seat the wear sensor (new), refit the caliper with the guide bolts, and reconnect the EPB actuator.\n8. Press the brake pedal several times to bed the piston against the new pad.\n9. Turn the ignition on, pull and release the EPB switch, then press and release the EPB switch — this exits service mode and re-tensions the cables.\n10. Top up brake fluid if necessary and run the brake test bench procedure (or do a careful low-speed bedding cycle).',
   '7 mm hexagonal wrench, BMW caliper piston tool 5 A1A 1E6 (or equivalent), OBD scan tool with EPB service mode (ISTA, Foxwell, Autel, Carly), brake fluid, brake caliper grease, new brake pad wear sensors, new EPB actuator bolts, battery charger',
   'Trying to wind the piston back manually (destroys the actuator); reusing the old wear sensor; forcing the spindle past its stop during emergency release; not renewing the actuator mounting bolts (BMW spec: single-use); doing the procedure on a low battery (the EPB will not complete service mode and may set DTCs)'),
  (@gen_lci, 'maintenance', 'epb-service-mode', 'Electronic parking brake service mode and brake pad renewal — 5 Series (G30)',
   '## Why EPB service mode matters\nThe G30 uses motor-on-caliper electronic parking brake actuators on each rear caliper. The rear caliper piston cannot be wound back manually because the EPB motor controls its retraction. Without putting the EPB into service mode (or executing the emergency release sequence) you cannot retract the piston to fit new pads, and forcing it will destroy the actuator gearbox.\n\n## Battery check first\nThe EPB drains substantial current during the cycle. Ensure the main battery (luggage compartment) is fully charged or hook up a stabilised charger. On vehicles with 48V mild-hybrid systems (any G30 LCI mHev variant) the additional 48V battery must also be active — check both.\n\n## Service mode via iDrive / OBD\n1. Block the front wheels and move the gear selector to P.\n2. Connect a battery charger or hook to an auxiliary 12V source.\n3. Activate EPB service mode via a compatible OBD scan tool (ISTA/D, Foxwell, Carly, Autel etc.) or via the iDrive **Vehicle settings → Service → Brake pad change** menu where present.\n4. The EPB motors will fully retract; a service icon appears in the instrument cluster.\n\n## Mechanical emergency release (if the EPB will not respond)\n1. Release the parking brake, turn the ignition off, and wait 30 seconds.\n2. Disconnect the EPB actuator electrical connector (A) and the brake servo hose (B).\n3. Remove the mounting bolts (C) and the actuator bracket (D).\n4. With the actuator off the caliper, use a 7 mm hexagonal wrench to turn the spindle clockwise to release the brake — do **not** turn the spindle fully to its stop, or the internal mechanism may bind.\n5. Inspect the spindle seal; renew if damaged. Lubricate the contact surfaces with brake fluid before reassembly.\n6. Refit the actuator and bracket using **new** mounting bolts. Reconnect the servo hose and electrical connector.\n7. Repeat on the opposite side.\n\n## Brake pad renewal\n1. Raise the vehicle and remove the rear wheels.\n2. Disconnect the brake pad wear sensor and **renew** it (BMW classes the sensor as a single-use part — always replace).\n3. Disconnect the EPB actuator connector.\n4. Remove the caliper guide bolts, swing the caliper off, and tie it up so the brake hose does not bear weight.\n5. Remove the pads and the retaining springs. Use the BMW caliper-piston tool 5 A1A 1E6 (or equivalent) to press the piston back — **do not** rotate the piston, as the G30 rear pistons are linear (not threaded like older E-series).\n6. Clean the caliper carrier, lubricate the guide pins with brake-specific grease, and inspect the boots — renew any cracked.\n7. Fit new pads, re-seat the wear sensor (new), refit the caliper with the guide bolts, and reconnect the EPB actuator.\n8. Press the brake pedal several times to bed the piston against the new pad.\n9. Turn the ignition on, pull and release the EPB switch, then press and release the EPB switch — this exits service mode and re-tensions the cables.\n10. Top up brake fluid if necessary and run the brake test bench procedure (or do a careful low-speed bedding cycle).',
   '7 mm hexagonal wrench, BMW caliper piston tool 5 A1A 1E6 (or equivalent), OBD scan tool with EPB service mode (ISTA, Foxwell, Autel, Carly), brake fluid, brake caliper grease, new brake pad wear sensors, new EPB actuator bolts, battery charger',
   'Trying to wind the piston back manually (destroys the actuator); reusing the old wear sensor; forcing the spindle past its stop during emergency release; not renewing the actuator mounting bolts (BMW spec: single-use); doing the procedure on a low battery (the EPB will not complete service mode and may set DTCs)');

-- 4. Automatic transmission fluid check + drain/refill (ZF GA8HP-50Z)
INSERT IGNORE INTO procedures (generation_id, procedure_type, slug, title, body_md, tools_required, common_mistakes)
VALUES
  (@gen_pre, 'maintenance', 'at-fluid-zf-8hp', 'Automatic transmission fluid check and drain/refill (ZF GA8HP-50Z) — 5 Series (G30)',
   '## "Filled for life" doesn''t mean "never change"\nThe G30 uses the ZF 8-speed automatic (GA8HP-50Z, internal BMW name). BMW marks the box as "filled for life" but in practice the fluid degrades after 60–100k km — especially on M550i / M5 V8 variants and 540d xDrive towing applications. Independent BMW specialists routinely change the fluid at 60–80k mi (100–130k km).\n\nThe transmission has **no dipstick**. Fluid level is set thermally — once the gearbox is at a specific test temperature, the side-fill plug doubles as the level reference: oil overflows when full and stops when level is reached.\n\n## Drain\n1. Raise the vehicle on a level lift (or use four jack stands).\n2. Remove the underbody trays. Locate the transmission pan — drain plug (2) is the lower one, filler plug (1) is the side-fill plug at mid-height on the pan.\n3. Place a clean catch pan and remove the drain plug. Around 4–5 L will come out (the rest sits in the torque converter).\n4. Renew the drain plug seal.\n5. Refit the drain plug. Torque: **8 Nm** (single-use — renew with each service).\n\n## Refill\n1. Remove the side-fill plug. Use BMW special tool 2 405 614 (torque wrench/fill adaptor) or an equivalent ZF refill kit.\n2. Refill via the side port. Initial fill from dry (including torque converter) is **8.8 L** — a drain-and-refill will typically take 4.5–5.5 L back in.\n3. Use ZF Lifeguard 8 (or BMW-approved equivalent meeting the GA8HP-50Z spec). Do not substitute generic ATF.\n\n## Level setting (thermal check)\n1. Connect an OBD scan tool that can read transmission oil temperature live (ISTA, BimmerLink, Foxwell etc.).\n2. Start the engine with the gear selector in P. Cycle through R, N, D, then back to P, pausing 5 seconds in each.\n3. Bring the transmission fluid up to **30–40 °C** initially.\n4. From the scan tool''s service menu, follow the ZF 8HP level-check procedure. Confirm fluid temperature stays in the **40–50 °C** window throughout the check.\n5. With the engine still running and the gearbox at 40–50 °C, remove the filler plug. A thin stream of fluid should escape. If nothing comes out, top up via the filler port until it does, then let surplus drip until the stream just slows.\n6. Refit the filler plug with a **new** seal. Torque: **35 Nm**.\n\nNever check the level when the box is cold (will read low and you''ll overfill) or hot (will read high and you''ll underfill).',
   'BMW/ZF refill tool 2 405 614, OBD scan tool with live transmission temperature, ZF Lifeguard 8 ATF (5–10 L), new drain plug, new filler plug, new seals',
   'Checking level when cold (fluid contracts — leads to overfill); reusing the drain or filler plug (single-use); using generic ATF instead of ZF Lifeguard 8 (causes harsh shifts and code SBC); skipping the cycle-through-gears warm-up step (oil sits in the converter and reads low)'),
  (@gen_lci, 'maintenance', 'at-fluid-zf-8hp', 'Automatic transmission fluid check and drain/refill (ZF GA8HP-50Z) — 5 Series (G30)',
   '## "Filled for life" doesn''t mean "never change"\nThe G30 uses the ZF 8-speed automatic (GA8HP-50Z, internal BMW name). BMW marks the box as "filled for life" but in practice the fluid degrades after 60–100k km — especially on M550i / M5 V8 variants and 540d xDrive towing applications. Independent BMW specialists routinely change the fluid at 60–80k mi (100–130k km).\n\nThe transmission has **no dipstick**. Fluid level is set thermally — once the gearbox is at a specific test temperature, the side-fill plug doubles as the level reference: oil overflows when full and stops when level is reached.\n\n## Drain\n1. Raise the vehicle on a level lift (or use four jack stands).\n2. Remove the underbody trays. Locate the transmission pan — drain plug (2) is the lower one, filler plug (1) is the side-fill plug at mid-height on the pan.\n3. Place a clean catch pan and remove the drain plug. Around 4–5 L will come out (the rest sits in the torque converter).\n4. Renew the drain plug seal.\n5. Refit the drain plug. Torque: **8 Nm** (single-use — renew with each service).\n\n## Refill\n1. Remove the side-fill plug. Use BMW special tool 2 405 614 (torque wrench/fill adaptor) or an equivalent ZF refill kit.\n2. Refill via the side port. Initial fill from dry (including torque converter) is **8.8 L** — a drain-and-refill will typically take 4.5–5.5 L back in.\n3. Use ZF Lifeguard 8 (or BMW-approved equivalent meeting the GA8HP-50Z spec). Do not substitute generic ATF.\n\n## Level setting (thermal check)\n1. Connect an OBD scan tool that can read transmission oil temperature live (ISTA, BimmerLink, Foxwell etc.).\n2. Start the engine with the gear selector in P. Cycle through R, N, D, then back to P, pausing 5 seconds in each.\n3. Bring the transmission fluid up to **30–40 °C** initially.\n4. From the scan tool''s service menu, follow the ZF 8HP level-check procedure. Confirm fluid temperature stays in the **40–50 °C** window throughout the check.\n5. With the engine still running and the gearbox at 40–50 °C, remove the filler plug. A thin stream of fluid should escape. If nothing comes out, top up via the filler port until it does, then let surplus drip until the stream just slows.\n6. Refit the filler plug with a **new** seal. Torque: **35 Nm**.\n\nNever check the level when the box is cold (will read low and you''ll overfill) or hot (will read high and you''ll underfill).',
   'BMW/ZF refill tool 2 405 614, OBD scan tool with live transmission temperature, ZF Lifeguard 8 ATF (5–10 L), new drain plug, new filler plug, new seals',
   'Checking level when cold (fluid contracts — leads to overfill); reusing the drain or filler plug (single-use); using generic ATF instead of ZF Lifeguard 8 (causes harsh shifts and code SBC); skipping the cycle-through-gears warm-up step (oil sits in the converter and reads low)');

-- ---------------------------------------------------------------------------
-- Source citations: HaynesPro + owner's manual on every new procedure row
-- ---------------------------------------------------------------------------
INSERT IGNORE INTO spec_sources (spec_table, spec_id, source_id)
SELECT 'procedures', id, @s_haynes FROM procedures
WHERE generation_id IN (@gen_pre, @gen_lci)
  AND slug IN ('oil-level-check', 'coolant-drain-refill', 'epb-service-mode', 'at-fluid-zf-8hp');

INSERT IGNORE INTO spec_sources (spec_table, spec_id, source_id)
SELECT 'procedures', id, @s_pre_2019 FROM procedures
WHERE generation_id = @gen_pre
  AND slug IN ('oil-level-check', 'coolant-drain-refill', 'epb-service-mode', 'at-fluid-zf-8hp')
  AND @s_pre_2019 IS NOT NULL;

INSERT IGNORE INTO spec_sources (spec_table, spec_id, source_id)
SELECT 'procedures', id, @s_lci_2023 FROM procedures
WHERE generation_id = @gen_lci
  AND slug IN ('oil-level-check', 'coolant-drain-refill', 'epb-service-mode', 'at-fluid-zf-8hp')
  AND @s_lci_2023 IS NOT NULL;
